nodes.notes:
GitHub - manage PRs, issues, discussions, notifications, and repos.

Actions:
  list_prs - list pull requests for a repo. Optional: repo, state (open/closed/all), limit.
  read_pr - show details of a specific PR. Requires: pr_number. Optional: repo.
  read_pr_comments - read conversation comments on a PR. Requires: pr_number. Optional: repo, limit.
  list_issues - list issues for a repo. Optional: repo, state (open/closed/all), labels, limit.
  read_issue - show details of a specific issue. Requires: issue_number. Optional: repo.
  list_notifications - list your unread GitHub notifications. Optional: limit.
  list_repos - list your recent repositories. Optional: limit.
  list_discussions - list the 3 most recent discussions. Optional: repo.
  read_discussion - read a discussion's post and list commenters. Requires: discussion_number. Optional: repo.
  read_discussion_comment - read a discussion comment in full with replies. Requires: comment_id.
  create_issue - create a new issue. Requires: title. Optional: repo, body, labels.
  comment - comment on a PR or issue. Requires: issue_number, body. Optional: repo.
  comment_discussion - post a top-level comment on a discussion. Requires: discussion_number, body. Optional: repo.
  reply_discussion_comment - reply to a specific discussion comment. Requires: discussion_id, comment_id, body.
  merge_pr - merge a pull request. Requires: pr_number. Optional: repo, merge_method (merge/squash/rebase).
  close_issue - close an issue. Requires: issue_number. Optional: repo.

Rules:
- repo defaults to ${GITHUB_DEFAULT_REPO} if not specified.
- pr_number and issue_number come from list_prs or list_issues. Never fabricate numbers.
- discussion_number comes from list_discussions. comment_id and discussion_id come from read_discussion.
- merge_pr is irreversible. Confirm with user before calling.

Chaining:
- "Any open PRs?" -> list_prs
- "Show me PR 84" -> read_pr pr_number 84
- "Read the comments on PR 84" -> read_pr_comments pr_number 84
- "What issues are open?" -> list_issues
- "Create an issue about the login bug" -> create_issue title "Login bug"
- "Merge PR 84" -> merge_pr pr_number 84
- "Any notifications?" -> list_notifications
- "Check the latest discussions" -> list_discussions
- "Read discussion 89" -> read_discussion discussion_number 89
- "Read nerdbeast's comment" -> read_discussion_comment comment_id DC_xxx
- "Reply to that comment" -> reply_discussion_comment discussion_id D_xxx comment_id DC_xxx body "..."

---schema
{
  "action": {
    "type": "string",
    "description": "One of: list_prs, read_pr, read_pr_comments, list_issues, read_issue, list_notifications, list_repos, list_discussions, read_discussion, read_discussion_comment, create_issue, comment, comment_discussion, reply_discussion_comment, merge_pr, close_issue",
    "required": true
  },
  "repo": {
    "type": "string",
    "description": "GitHub repo in owner/repo format. Defaults to configured default repo."
  },
  "pr_number": {
    "type": "integer",
    "description": "Pull request number. For: read_pr, read_pr_comments, merge_pr"
  },
  "issue_number": {
    "type": "integer",
    "description": "Issue number. For: read_issue, close_issue, comment"
  },
  "discussion_number": {
    "type": "integer",
    "description": "Discussion number. For: read_discussion, comment_discussion"
  },
  "comment_id": {
    "type": "string",
    "description": "Comment node ID. For: read_discussion_comment, reply_discussion_comment"
  },
  "discussion_id": {
    "type": "string",
    "description": "Discussion node ID. For: reply_discussion_comment"
  },
  "state": {
    "type": "string",
    "description": "Filter by state: open, closed, all. Default: open. For: list_prs, list_issues"
  },
  "title": {
    "type": "string",
    "description": "Issue title. For: create_issue"
  },
  "body": {
    "type": "string",
    "description": "Body text. For: create_issue, comment, comment_discussion, reply_discussion_comment"
  },
  "labels": {
    "type": "string",
    "description": "Comma-separated labels. For: list_issues, create_issue"
  },
  "merge_method": {
    "type": "string",
    "description": "Merge method: merge, squash, rebase. Default: merge. For: merge_pr"
  },
  "limit": {
    "type": "integer",
    "description": "Max results. Default 5."
  }
}

parameters.jsCode:
let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase().trim();

if (!action) {
  return [{ json: { error: true, message: 'Action is required. Use one of: list_prs, read_pr, read_pr_comments, list_issues, read_issue, list_notifications, list_repos, list_discussions, read_discussion, read_discussion_comment, create_issue, comment, comment_discussion, reply_discussion_comment, merge_pr, close_issue.' } }];
}

const categoryMap = {
  list_prs: 'read',
  read_pr: 'read',
  read_pr_comments: 'read',
  list_issues: 'read',
  read_issue: 'read',
  list_notifications: 'read',
  list_repos: 'read',
  list_discussions: 'read',
  read_discussion: 'read',
  read_discussion_comment: 'read',
  create_issue: 'write',
  comment: 'write',
  comment_discussion: 'write',
  reply_discussion_comment: 'write',
  merge_pr: 'manage',
  close_issue: 'manage'
};

const category = categoryMap[action] || '';

if (!category) {
  return [{ json: { error: true, message: `Unknown action: ${action}. Use one of: list_prs, read_pr, read_pr_comments, list_issues, read_issue, list_notifications, list_repos, list_discussions, read_discussion, read_discussion_comment, create_issue, comment, comment_discussion, reply_discussion_comment, merge_pr, close_issue.` } }];
}

const repo = data.repo || '${GITHUB_DEFAULT_REPO}';
const pr_number = parseInt(data.pr_number) || null;
const issue_number = parseInt(data.issue_number) || null;
const discussion_number = parseInt(data.discussion_number) || null;
const comment_id = data.comment_id || '';
const discussion_id = data.discussion_id || '';
const state = data.state || 'open';
const title = data.title || '';
const body = data.body || '';
const labels = data.labels || '';
const merge_method = data.merge_method || 'merge';
const limit = parseInt(data.limit) || 5;

return [{
  json: {
    action, category, repo, pr_number, issue_number, discussion_number, comment_id, discussion_id,
    state, title, body, labels, merge_method, limit
  }
}];

const allItems = $input.all().map(i => i.json);

if (allItems.length === 0 || (allItems.length === 1 && !allItems[0].number)) {
  return [{ json: { message: 'No pull requests found.', count: 0, pull_requests: [] } }];
}

const formatted = allItems.map(pr => ({
  number: pr.number,
  title: pr.title,
  state: pr.state,
  author: pr.user ? pr.user.login : 'unknown',
  created: pr.created_at ? pr.created_at.split('T')[0] : '',
  draft: pr.draft || false,
  labels: (pr.labels || []).map(l => l.name)
}));

const repo = $('Parse Parameters').item.json.repo;
let message = `${formatted.length} pull request${formatted.length === 1 ? '' : 's'} on ${repo}. `;
formatted.forEach(pr => {
  message += `Number ${pr.number}: ${pr.title} by ${pr.author}${pr.draft ? ' (draft)' : ''}. `;
});

return [{ json: { message: message.trim(), count: formatted.length, pull_requests: formatted } }];

const pr = $input.item.json;

const detail = {
  number: pr.number,
  title: pr.title,
  state: pr.state,
  author: pr.user ? pr.user.login : 'unknown',
  created: pr.created_at ? pr.created_at.split('T')[0] : '',
  merged: pr.merged || false,
  mergeable: pr.mergeable,
  draft: pr.draft || false,
  additions: pr.additions || 0,
  deletions: pr.deletions || 0,
  changed_files: pr.changed_files || 0,
  labels: (pr.labels || []).map(l => l.name),
  reviewers: (pr.requested_reviewers || []).map(r => r.login),
  body: pr.body ? pr.body.substring(0, 500) : ''
};

let message = `PR ${pr.number}: ${pr.title}. `;
message += `By ${detail.author}, ${detail.state}${detail.draft ? ' (draft)' : ''}. `;
message += `${detail.changed_files} file${detail.changed_files === 1 ? '' : 's'} changed, ${detail.additions} additions, ${detail.deletions} deletions.`;
if (detail.labels.length > 0) message += ` Labels: ${detail.labels.join(', ')}.`;
if (detail.reviewers.length > 0) message += ` Reviewers: ${detail.reviewers.join(', ')}.`;

return [{ json: { message, pull_request: detail } }];

const allItems = $input.all().map(i => i.json);
const prNum = $('Parse Parameters').item.json.pr_number;
const repo = $('Parse Parameters').item.json.repo;

if (allItems.length === 0 || (allItems.length === 1 && !allItems[0].id)) {
  return [{ json: { message: `No comments on PR ${prNum}.`, count: 0, comments: [] } }];
}

const formatted = allItems.map(c => ({
  id: c.id,
  author: c.user ? c.user.login : 'unknown',
  body: c.body || '',
  created: c.created_at ? c.created_at.split('T')[0] : '',
  association: c.author_association || ''
}));

let message = `${formatted.length} comment${formatted.length === 1 ? '' : 's'} on PR ${prNum}. `;
formatted.forEach(c => {
  const preview = c.body.length > 200 ? c.body.substring(0, 200) + '...' : c.body;
  message += `${c.author} says: ${preview} `;
});

return [{ json: { message: message.trim(), count: formatted.length, comments: formatted } }];

const allItems = $input.all().map(i => i.json).filter(i => !i.pull_request);

if (allItems.length === 0) {
  return [{ json: { message: 'No issues found.', count: 0, issues: [] } }];
}

const formatted = allItems.map(i => ({
  number: i.number,
  title: i.title,
  state: i.state,
  author: i.user ? i.user.login : 'unknown',
  created: i.created_at ? i.created_at.split('T')[0] : '',
  labels: (i.labels || []).map(l => l.name),
  comments: i.comments || 0
}));

const repo = $('Parse Parameters').item.json.repo;
let message = `${formatted.length} issue${formatted.length === 1 ? '' : 's'} on ${repo}. `;
formatted.forEach(i => {
  message += `Number ${i.number}: ${i.title} by ${i.author}. `;
});

return [{ json: { message: message.trim(), count: formatted.length, issues: formatted } }];

const i = $input.item.json;

const detail = {
  number: i.number,
  title: i.title,
  state: i.state,
  author: i.user ? i.user.login : 'unknown',
  created: i.created_at ? i.created_at.split('T')[0] : '',
  labels: (i.labels || []).map(l => l.name),
  comments: i.comments || 0,
  assignees: (i.assignees || []).map(a => a.login),
  body: i.body ? i.body.substring(0, 500) : ''
};

let message = `Issue ${i.number}: ${i.title}. `;
message += `By ${detail.author}, ${detail.state}. `;
if (detail.comments > 0) message += `${detail.comments} comment${detail.comments === 1 ? '' : 's'}. `;
if (detail.labels.length > 0) message += `Labels: ${detail.labels.join(', ')}. `;
if (detail.assignees.length > 0) message += `Assigned to: ${detail.assignees.join(', ')}. `;

return [{ json: { message: message.trim(), issue: detail } }];

const allItems = $input.all().map(i => i.json);

if (allItems.length === 0 || (allItems.length === 1 && !allItems[0].id)) {
  return [{ json: { message: 'No unread notifications.', count: 0, notifications: [] } }];
}

const formatted = allItems.map(n => ({
  id: n.id,
  reason: n.reason,
  title: n.subject ? n.subject.title : 'Unknown',
  type: n.subject ? n.subject.type : 'Unknown',
  repo: n.repository ? n.repository.full_name : 'Unknown',
  updated: n.updated_at ? n.updated_at.split('T')[0] : ''
}));

let message = `You have ${formatted.length} unread notification${formatted.length === 1 ? '' : 's'}. `;
formatted.forEach(n => {
  message += `${n.type} on ${n.repo}: ${n.title}. `;
});

return [{ json: { message: message.trim(), count: formatted.length, notifications: formatted } }];

const allItems = $input.all().map(i => i.json);

if (allItems.length === 0 || (allItems.length === 1 && !allItems[0].full_name)) {
  return [{ json: { message: 'No repositories found.', count: 0, repos: [] } }];
}

const formatted = allItems.map(r => ({
  name: r.full_name,
  description: r.description || '',
  private: r.private,
  language: r.language || '',
  stars: r.stargazers_count || 0,
  open_issues: r.open_issues_count || 0,
  updated: r.updated_at ? r.updated_at.split('T')[0] : ''
}));

let message = `You have ${formatted.length} recent repo${formatted.length === 1 ? '' : 's'}. `;
formatted.forEach(r => {
  message += `${r.name}${r.private ? ' (private)' : ''}`;
  if (r.open_issues > 0) message += `, ${r.open_issues} open issue${r.open_issues === 1 ? '' : 's'}`;
  message += '. ';
});

return [{ json: { message: message.trim(), count: formatted.length, repos: formatted } }];

const i = $input.item.json;
const repo = $('Parse Parameters').item.json.repo;

return [{ json: { message: `Issue ${i.number} created on ${repo}: ${i.title}.`, issue_number: i.number, url: i.html_url, success: true } }];

const c = $input.item.json;
const num = $('Parse Parameters').item.json.issue_number;
const repo = $('Parse Parameters').item.json.repo;

return [{ json: { message: `Comment posted on ${repo} number ${num}.`, url: c.html_url, success: true } }];

const result = $input.item.json;
const num = $('Parse Parameters').item.json.pr_number;
const repo = $('Parse Parameters').item.json.repo;

if (result.merged) {
  return [{ json: { message: `PR ${num} on ${repo} has been merged.`, success: true } }];
} else {
  return [{ json: { message: `Could not merge PR ${num}. ${result.message || ''}`, success: false } }];
}

const i = $input.item.json;
const repo = $('Parse Parameters').item.json.repo;

return [{ json: { message: `Issue ${i.number} on ${repo} has been closed.`, success: true } }];

const data = $input.item.json;
const nodes = data.data && data.data.repository && data.data.repository.discussions ? data.data.repository.discussions.nodes : [];

if (nodes.length === 0) {
  return [{ json: { message: 'No discussions found.', count: 0, discussions: [] } }];
}

const formatted = nodes.map(d => ({
  number: d.number,
  title: d.title,
  author: d.author ? d.author.login : 'unknown',
  category: d.category ? d.category.name : '',
  created: d.createdAt ? d.createdAt.split('T')[0] : '',
  comments: d.comments ? d.comments.totalCount : 0
}));

const repo = $('Parse Parameters').item.json.repo;
let message = `${formatted.length} recent discussion${formatted.length === 1 ? '' : 's'} on ${repo}. `;
formatted.forEach(d => {
  message += `Number ${d.number}: ${d.title} by ${d.author} in ${d.category}. `;
});

return [{ json: { message: message.trim(), count: formatted.length, discussions: formatted } }];

const data = $input.item.json;
const num = $('Parse Parameters').item.json.discussion_number;
const repo = $('Parse Parameters').item.json.repo;
const title = $('Get Discussion ID').item.json.data.repository.discussion.title;

if (data.errors) {
  return [{ json: { message: 'Failed to reply to discussion. ' + (data.errors[0] ? data.errors[0].message : ''), error: true } }];
}

return [{ json: { message: `Comment posted on discussion ${num}: ${title}.`, success: true } }];

const data = $input.item.json;
const d = data.data && data.data.repository ? data.data.repository.discussion : null;

if (!d) {
  return [{ json: { message: 'Discussion not found.', error: true } }];
}

const totalComments = d.comments ? d.comments.totalCount : 0;
const commentNodes = d.comments && d.comments.nodes ? d.comments.nodes : [];

const comments = commentNodes.map(c => ({
  comment_id: c.id,
  author: c.author ? c.author.login : 'unknown',
  body: c.body ? c.body.substring(0, 200) : '',
  created: c.createdAt ? c.createdAt.split('T')[0] : ''
}));

const detail = {
  discussion_id: d.id,
  number: d.number,
  title: d.title,
  author: d.author ? d.author.login : 'unknown',
  category: d.category ? d.category.name : '',
  created: d.createdAt ? d.createdAt.split('T')[0] : '',
  body: d.body ? d.body.substring(0, 300) : '',
  comment_count: totalComments,
  comments: comments
};

let message = `Discussion ${d.number}: ${d.title}. Posted by ${detail.author} in ${detail.category}. `;
if (totalComments > 0) {
  const authors = [...new Set(comments.map(c => c.author))];
  message += `${totalComments} comment${totalComments === 1 ? '' : 's'} from ${authors.join(', ')}. `;
} else {
  message += 'No comments yet. ';
}

return [{ json: { message: message.trim(), discussion: detail } }];

const data = $input.item.json;
const c = data.data && data.data.node ? data.data.node : null;

if (!c) {
  return [{ json: { message: 'Comment not found.', error: true } }];
}

const replies = c.replies && c.replies.nodes ? c.replies.nodes : [];
const totalReplies = c.replies ? c.replies.totalCount : 0;

const detail = {
  comment_id: c.id,
  author: c.author ? c.author.login : 'unknown',
  body: c.body || '',
  created: c.createdAt ? c.createdAt.split('T')[0] : '',
  reply_count: totalReplies,
  replies: replies.map(r => ({
    comment_id: r.id,
    author: r.author ? r.author.login : 'unknown',
    body: r.body ? r.body.substring(0, 200) : '',
    created: r.createdAt ? r.createdAt.split('T')[0] : ''
  }))
};

let message = `${detail.author} says: ${c.body ? c.body.substring(0, 300) : ''}. `;
if (totalReplies > 0) {
  const replyAuthors = [...new Set(replies.map(r => r.author ? r.author.login : 'unknown'))];
  message += `${totalReplies} repl${totalReplies === 1 ? 'y' : 'ies'} from ${replyAuthors.join(', ')}.`;
}

return [{ json: { message: message.trim(), comment: detail } }];

const data = $input.item.json;

if (data.errors) {
  return [{ json: { message: 'Failed to reply. ' + (data.errors[0] ? data.errors[0].message : ''), error: true } }];
}

return [{ json: { message: 'Reply posted.', success: true } }];

const errorData = $input.item.json;

if (errorData.error === true && errorData.message) {
  return [{ json: { message: errorData.message, error: true } }];
}

let errorMsg = errorData.message || errorData.error || 'Unknown error';

if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}

if (errorMsg.includes('401') || errorMsg.includes('Bad credentials')) {
  errorMsg = 'GitHub authentication failed. Please check your personal access token.';
} else if (errorMsg.includes('403') || errorMsg.includes('rate limit')) {
  errorMsg = 'GitHub rate limit reached or access denied. Try again later.';
} else if (errorMsg.includes('404') || errorMsg.includes('Not Found')) {
  errorMsg = 'Not found. Check the repo name, PR number, or issue number.';
} else if (errorMsg.includes('422')) {
  errorMsg = 'Invalid request. Check your parameters.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to GitHub. Check your internet connection.';
}

return [{ json: { message: 'GitHub error: ' + errorMsg, error: true } }];
